package github.chains;

import spoon.Launcher;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtFieldAccess;
import spoon.reflect.code.CtImport;
import spoon.reflect.declaration.CtType;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtTypeReference;

import java.io.File;
import java.util.List;

/**
 * Generic Spoon transformation to fix zip4j core package removal issue.
 * This transformation fixes the issue where net.lingala.zip4j.core.ZipFile
 * was removed in zip4j version 2.11.1 and is now directly in net.lingala.zip4j.ZipFile
 */
public class Main {
    public static void main(String[] args) {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source_directory>");
            System.exit(1);
        }

        String sourceDirectory = args[0];

        Launcher launcher = new Launcher();
        launcher.addInputResource(sourceDirectory);
        launcher.setSourceOutputDirectory(sourceDirectory + "/transformed");
        launcher.getEnvironment().setAutoImports(true);
        launcher.getEnvironment().setComplianceLevel(8);

        launcher.buildModel();
        Factory factory = launcher.getFactory();

        // Find all imports that reference net.lingala.zip4j.core.ZipFile
        List<CtImport> imports = factory.getModel().getElements(
            e -> e instanceof CtImport && 
                 e.toString().contains("net.lingala.zip4j.core.ZipFile")
        );

        for (CtImport imp : imports) {
            // Replace the import
            String importString = imp.toString();
            if (importString.contains("net.lingala.zip4j.core.ZipFile")) {
                String newImport = importString.replace(
                    "net.lingala.zip4j.core.ZipFile",
                    "net.lingala.zip4j.ZipFile"
                );
                imp.setReference(factory.createImport(factory.createTypeReference(newImport)));
            }
        }

        // Find all field accesses that reference net.lingala.zip4j.core.ZipFile
        List<CtFieldAccess> fieldAccesses = factory.getModel().getElements(
            e -> e instanceof CtFieldAccess && 
                 e.toString().contains("net.lingala.zip4j.core.ZipFile")
        );

        for (CtFieldAccess fieldAccess : fieldAccesses) {
            String fieldAccessString = fieldAccess.toString();
            if (fieldAccessString.contains("net.lingala.zip4j.core.ZipFile")) {
                // Replace the reference in the field access
                String newFieldAccess = fieldAccessString.replace(
                    "net.lingala.zip4j.core.ZipFile",
                    "net.lingala.zip4j.ZipFile"
                );
                // Update the field access expression
                CtExpression<?> newExpression = factory.createCodeSnippetExpression(newFieldAccess);
                fieldAccess.replace(newExpression);
            }
        }

        // Generate the modified code
        launcher.writeProcessedSourceFiles();

        System.out.println("Transformation completed successfully.");
    }
}

